#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
    controller->has_valid_temperature = false;
    controller->has_valid_level = false;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Fill-and-heat control policy */
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        if (!controller->has_valid_temperature) {
            // First valid temperature seen - set to safe idle
            controller_set_safe_idle(controller);
        } else {
            controller->previous_temperature_c = controller->last_temperature_c;
            controller->last_temperature_c = input.temperature_c;
            controller->last_temperature_ms = input.now_ms;

            /* Control decisions based on temperature */
            if (input.temperature_c < 55) {
                /* If level is low (<60), open inlet and turn off heater */
                if (controller->last_level < 60) {
                    controller->inlet_open = true;
                    controller->heater_on = false;
                    output.state = CONTROLLER_STATE_FILLING;
                    output.state_name = "STATE FILLING";
                } else {
                    /* Level is safe, but temperature low - keep heater off */
                    controller->inlet_open = false;
                    controller->heater_on = false;
                    output.state = CONTROLLER_STATE_SAFE_IDLE;
                    output.state_name = "STATE SAFE_IDLE";
                }
            } else if (input.temperature_c < 45) {
                /* Very low temperature - keep heater off */
                controller->inlet_open = false;
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
            } else if (input.temperature_c < 47) {
                /* Temperature in [45, 47) - heater off */
                controller->inlet_open = false;
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
            } else if (input.temperature_c < 48) {
                /* Temperature in [47, 48) - heater off */
                controller->inlet_open = false;
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
            } else if (input.temperature_c >= 47 && input.temperature_c <= 48) {
                /* Near upper band [47, 48] - check if rising */
                if (!controller->has_valid_temperature) {
                    controller_set_safe_idle(controller);
                } else {
                    /* Check if temperature is rising compared to previous valid sample */
                    int current_temp = input.temperature_c;
                    int prev_temp = controller->previous_temperature_c;

                    if (current_temp > prev_temp) {
                        /* Rising temperature - turn heater off early but stay in HOLDING state */
                        controller->inlet_open = false;
                        controller->heater_on = false;
                        output.state = CONTROLLER_STATE_HOLDING;
                        output.state_name = "STATE HOLDING";
                    } else {
                        /* Not rising - preserve safe heater state (heater off) */
                        controller->inlet_open = false;
                        controller->heater_on = false;
                        output.state = CONTROLLER_STATE_SAFE_IDLE;
                        output.state_name = "STATE SAFE_IDLE";
                    }
                }
            } else {
                /* Temperature > 48 - heater off */
                controller->inlet_open = false;
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
            }
        }

        break;
    case CONTROLLER_INPUT_LEVEL:
        if (!controller->has_valid_level) {
            // First valid level seen - set to safe idle
            controller_set_safe_idle(controller);
        } else {
            controller->previous_temperature_c = controller->last_temperature_c;
            controller->last_temperature_c = 0;
            controller->last_level_ms = input.now_ms;

            /* Control decisions based on level */
            if (input.level < 60) {
                /* If level is low (<60), open inlet and turn off heater */
                controller->inlet_open = true;
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_FILLING;
                output.state_name = "STATE FILLING";
            } else if (input.level > 75) {
                /* If level is high (>75), close inlet */
                controller->inlet_open = false;
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
            } else if (input.level < 55) {
                /* Low level - keep heater off */
                controller->inlet_open = true;
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_FILLING;
                output.state_name = "STATE FILLING";
            } else if (input.level >= 60 && input.level <= 75) {
                /* Level in [60, 75] and temperature low - heater on */
                controller->heater_on = true;
                output.state = CONTROLLER_STATE_HEATING;
                output.state_name = "STATE HEATING";
            } else if (input.level >= 60 && input.level <= 75) {
                /* Level in [60, 75] - heater off */
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
            } else if (input.level < 55) {
                /* Very low level - keep heater off */
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
            } else {
                /* Normal level range - heater off */
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
            }
        }

        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Timeout or malformed input - fail safe */
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No new data - keep current state */
        if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
            controller_set_safe_idle(controller);
        } else {
